from EfiPy2.Lib.Reset import Reset, EfiResetCold, EfiResetWarm, EfiResetShutdown, EfiResetPlatformSpecific

def ResetShutdownCmd (Shutdown = False):
    import argparse

    parser = argparse.ArgumentParser (prog = 'EfiPy2Reset.py')

    SoftBootArg     = parser.add_argument ('-s', '--soft', action = 'store_true', help = 'soft reset.')
    WarmBootArg     = parser.add_argument ('-w', '--warm', action = 'store_true', help = 'warn reset.')
    ColdBootArg     = parser.add_argument ('-c', '--cold', action = 'store_true', help = 'cold reset.')
    AcpiBootArg     = parser.add_argument ('-a', '--acpi', action = 'store_true', help = 'system reset via ACPI.')
    KeyboardBootArg = parser.add_argument ('-k', '--keyboard', action = 'store_true', help = 'system reset via keyboard IO port 60/64.')
    Port92BootArg   = parser.add_argument ('-p', '--port92', action = 'store_true', help = 'system reset via port 92h.')
    UefiBootArg     = parser.add_argument ('-u', '--uefi', action = 'store_true', help = 'UEFI gRT.ResetSystem operation')
    ShutdownArg     = parser.add_argument ('-d', '--shutdown', action = 'store_true', help = 'Shutdown via gRT.ResetSystem')
    DryRunArg       = parser.add_argument ('-r', '--dryrun', action = 'store_true', help = 'Dry run shutdown command')
    args = parser.parse_args ()

    ResetCommandList = (SoftBootArg, WarmBootArg, ColdBootArg, AcpiBootArg, KeyboardBootArg, Port92BootArg, ShutdownArg)

    if sum ((args.soft, args.warm, args.cold, args.acpi, args.keyboard, args.port92, args.shutdown)) > 1:
        print (f'Only one or none of below argument are allowed in this program...')
        for ResetCommand in ResetCommandList:
            print (ResetCommand.option_strings, ResetCommand.help)
        return

    DryRun = True if args.dryrun else False

    if args.soft:
        print (f'Process "{SoftBootArg.help}"')
        Reset.Cf9Reset (0x04, DryRun)
    elif args.warm:
        print (f'Process "{WarmBootArg.help}"')
        if args.uefi == True:
            Reset.UefiOp (EfiResetWarm, DryRun)
        else:
            Reset.Cf9Reset (0x06, DryRun)
    elif args.cold:
        print (f'Process "{ColdBootArg.help}"')
        if args.uefi == True:
            Reset.UefiOp (EfiResetCold, DryRun)
        else:
            Reset.Cf9Reset (0x0E, DryRun)
    elif args.acpi:
        print (f'Process "{AcpiBootArg.help}"')
        Reset.AcpiReset (DryRun)
    elif args.port92:
        print (f'Process "{Port92BootArg.help}"')
        Reset.PortReset (0x92, 0x01, DryRun)
    elif args.keyboard:
        print (f'Process "{KeyboardBootArg.help}"')
        Reset.KeyboardReset (DryRun)
    elif args.shutdown:
        print (f'Process "{ShutdownArg.help}"')
        Reset.UefiOp (EfiResetShutdown, DryRun)
    elif args.uefi:
        print (f'Process "{UefiBootArg.help}"')
        Reset.UefiOp (EfiResetPlatformSpecific, DryRun)
    elif Shutdown == True:
        print (f'Process "{ShutdownArg.help}"')
        Reset.UefiOp (EfiResetShutdown, DryRun)
    else:
        print (f'Process "{ColdBootArg.help}"')
        Reset.Cf9Reset (0x0E, DryRun)

if __name__ == '__main__':
    ResetShutdownCmd ()